mapper.insert:
INSERT IGNORE INTO risk_case(
    case_id, decision_id, status, queue, assignee, result, evidence_json, create_time, update_time
) VALUES(
    #{caseId}, #{decisionId}, #{status}, #{queue}, #{assignee}, #{result}, #{evidenceJson}, NOW(), NOW()
)

mapper.select:
SELECT case_id, decision_id, status, queue, assignee, result, evidence_json, create_time, update_time
FROM risk_case
WHERE case_id = #{caseId}

mapper.update:
UPDATE risk_case
SET assignee = #{assignee},
    status = 'ASSIGNED',
    update_time = NOW()
WHERE case_id = #{caseId}
  AND status = #{expectedStatus}

mapper.select:
SELECT case_id, decision_id, status, queue, assignee, result, evidence_json, create_time, update_time
FROM risk_case
WHERE 1=1

    AND status = #{status}


    AND queue = #{queue}


    AND create_time >= #{beginTime}


    AND create_time <= #{endTime}

ORDER BY update_time DESC, case_id DESC
LIMIT #{limit} OFFSET #{offset}
